{
  "name": "GraceReflect - Christian Meditation Assistant",
  "description": "A spiritual sanctuary for Bible meditation, helping believers connect with God's word through AI-assisted reflection, application, and intercessory prayer."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MeditationResult {
  verse: string;
  meditation: string;
  application: string;
  prayer: string;
  intercessoryPrayer: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { MeditationResult } from "../types";

const SYSTEM_INSTRUCTION = `
너는 기독교 영성 멘토이자 성경 묵상 도우미이다.
사용자가 제공하는 성경 구절을 중심으로 깊이 있는 묵상문을 작성하라.

작성 가이드라인:
1. 말씀을 바탕으로 본문 내용을 요약하고 영적 의미를 해석한다.
2. 하나님이 오늘 나에게 주시는 메시지를 중심으로 묵상문을 쓴다.
3. 일상 속 적용점을 구체적으로 제시한다.
4. 짧은 개인 기도문을 작성한다.
5. 마지막으로 교회 중보기도팀을 위한 간절하고 풍성한 기도문으로 마무리한다.

전체적으로 경건하고 진솔하며, 하나님의 임재를 느낄 수 있는 은혜로운 어조를 유지하라.
응답은 반드시 지정된 JSON 구조로 반환하라.
`;

export const generateMeditation = async (verseInput: string): Promise<MeditationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `지금 다음 말씀으로 묵상문을 작성하라: ${verseInput}`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verse: { type: Type.STRING, description: "입력된 성경 구절과 해당 본문" },
          meditation: { type: Type.STRING, description: "본문의 의미와 하나님의 음성" },
          application: { type: Type.STRING, description: "오늘의 삶 속 실천점" },
          prayer: { type: Type.STRING, description: "개인 기도문" },
          intercessoryPrayer: { type: Type.STRING, description: "중보기도 팀원들을 위한 긴 기도문" }
        },
        required: ["verse", "meditation", "application", "prayer", "intercessoryPrayer"],
        propertyOrdering: ["verse", "meditation", "application", "prayer", "intercessoryPrayer"]
      }
    },
  });

  const resultStr = response.text;
  if (!resultStr) throw new Error("결과를 생성하지 못했습니다.");

  try {
    return JSON.parse(resultStr) as MeditationResult;
  } catch (e) {
    console.error("JSON parsing error:", e);
    throw new Error("응답 데이터 형식이 올바르지 않습니다.");
  }
};

