import React, { useState } from 'react';
import Header from './components/Header';
import LoadingState from './components/LoadingState';
import MeditationDisplay from './components/MeditationDisplay';
import { generateMeditation } from './services/geminiService';
import { MeditationResult, AppStatus } from './types';

const App: React.FC = () => {
  const [input, setInput] = useState('');
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [result, setResult] = useState<MeditationResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setStatus(AppStatus.LOADING);
    setError(null);

    try {
      const data = await generateMeditation(input);
      setResult(data);
      setStatus(AppStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setError(err.message || '묵상문을 생성하는 중에 오류가 발생했습니다.');
      setStatus(AppStatus.ERROR);
    }
  };

  const handleReset = () => {
    setInput('');
    setResult(null);
    setStatus(AppStatus.IDLE);
    setError(null);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6">
      <Header />

      <main className="mt-8">
        {status === AppStatus.IDLE && (
          <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4">
              <h3 className="text-2xl font-bold text-stone-800 serif-font">
                오늘의 말씀을 입력하세요
              </h3>
              <p className="text-stone-500 font-light">
                마음속에 머무는 구절이나 묵상하고 싶은 본문을 기록해주세요.
              </p>
            </div>

            <form onSubmit={handleGenerate} className="space-y-6">
              <div className="relative">
                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  placeholder="예: 시편 23:1 - 여호와는 나의 목자시니 내게 부족함이 없으리로다"
                  className="w-full min-h-[160px] p-6 text-lg border-2 border-stone-200 rounded-2xl focus:ring-2 focus:ring-stone-400 focus:border-stone-400 outline-none transition-all bg-white/80 backdrop-blur-sm shadow-sm placeholder:text-stone-300 serif-font"
                  required
                />
              </div>

              <button
                type="submit"
                disabled={!input.trim()}
                className={`w-full py-4 rounded-xl text-lg font-bold transition-all shadow-lg shadow-stone-200 flex items-center justify-center gap-2 ${
                  input.trim() 
                    ? 'bg-stone-800 text-white hover:bg-stone-700 active:scale-[0.98]' 
                    : 'bg-stone-200 text-stone-400 cursor-not-allowed'
                }`}
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
                </svg>
                묵상 시작하기
              </button>
            </form>

            <div className="pt-8 border-t border-stone-200">
              <p className="text-center text-xs text-stone-400 italic">
                "주의 말씀은 내 발에 등이요 내 길에 빛이니이다" (시 119:105)
              </p>
            </div>
          </div>
        )}

        {status === AppStatus.LOADING && <LoadingState />}

        {status === AppStatus.ERROR && (
          <div className="max-w-md mx-auto p-8 bg-red-50 rounded-2xl border border-red-100 text-center space-y-4">
            <div className="text-red-500 text-4xl">⚠️</div>
            <p className="text-red-800 font-medium">{error}</p>
            <button 
              onClick={handleReset}
              className="px-6 py-2 bg-red-100 text-red-700 rounded-lg hover:bg-red-200 transition-colors"
            >
              다시 시도하기
            </button>
          </div>
        )}

        {status === AppStatus.SUCCESS && result && (
          <MeditationDisplay data={result} onReset={handleReset} />
        )}
      </main>

      <footer className="mt-auto py-12 text-center text-stone-400 text-xs font-light tracking-wide">
        &copy; {new Date().getFullYear()} GraceReflect. All rights reserved.
      </footer>
    </div>
  );
};

export default App;

export interface MeditationResult {
  verse: string;
  meditation: string;
  mentorWisdom: string;
  application: string;
  prayer: string;
  intercessoryPrayer: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { MeditationResult } from "../types";

const SYSTEM_INSTRUCTION = `
너는 기독교 영성 멘토이자 성경 묵상 도우미이다.
사용자가 제공하는 성경 구절과 상황(고민)을 중심으로 깊이 있는 묵상문을 작성하라.

작성 가이드라인:
1. 말씀 본문의 핵심 의미를 해석한다.
2. 만약 사용자가 구체적인 상황(예: 자리 양보, 인간관계 등)을 제시했다면, 성경 구절과 그 상황을 직접적으로 연결하여 영적인 조언(mentorWisdom)을 제공하라.
3. 하나님이 오늘 공동체와 개인에게 주시는 메시지를 중심으로 묵상문을 쓴다.
4. 일상 속 적용점을 구체적으로 제시한다.
5. 짧은 개인 기도문을 작성한다.
6. 마지막으로 교회 중보기도팀을 위한 간절하고 풍성한 기도문으로 마무리한다.

전체적으로 경건하고 진솔하며, 하나님의 임재를 느끼게 하는 은혜로운 어조를 유지하라.
응답은 반드시 지정된 JSON 구조로 반환하라.
`;

export const generateMeditation = async (verseInput: string): Promise<MeditationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `사용자의 묵상 요청: ${verseInput}`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verse: { type: Type.STRING, description: "성경 구절 본문" },
          meditation: { type: Type.STRING, description: "본문의 영적 해석" },
          mentorWisdom: { type: Type.STRING, description: "사용자의 구체적 상황에 대한 멘토의 영적 조언" },
          application: { type: Type.STRING, description: "오늘의 삶 속 실천점" },
          prayer: { type: Type.STRING, description: "개인 기도문" },
          intercessoryPrayer: { type: Type.STRING, description: "중보기도 팀을 위한 기도문" }
        },
        required: ["verse", "meditation", "mentorWisdom", "application", "prayer", "intercessoryPrayer"],
        propertyOrdering: ["verse", "meditation", "mentorWisdom", "application", "prayer", "intercessoryPrayer"]
      }
    },
  });

  const resultStr = response.text;
  if (!resultStr) throw new Error("결과를 생성하지 못했습니다.");

  try {
    return JSON.parse(resultStr) as MeditationResult;
  } catch (e) {
    console.error("JSON parsing error:", e);
    throw new Error("응답 데이터 형식이 올바르지 않습니다.");
  }
};

