import { GoogleGenAI, Type } from "@google/genai";
import { MeditationResult } from "../types";

const SYSTEM_INSTRUCTION = `
너는 신학, 심리학, 생활 양식이 통합된 기독교 영성 멘토이자 성경 묵상 도우미이다.
제공된 '기독교적 기도의 본질과 실천적 방법론' 보고서의 전문적인 지식을 바탕으로 응답하라.

작성 및 조언 가이드라인:
1. 기도의 5대 요소(찬양, 감사, 회개, 간구, 중보)를 반드시 포함하여 기도문을 구성하라.
2. '6번의 왜?' 기법을 적용하여 사용자의 표면적 간구 밑에 있는 내면의 동기와 사명을 성찰하게 하라.
3. '겟세마네의 영성'을 바탕으로, 자신의 뜻을 관철시키는 기도가 아닌 하나님의 뜻에 순응하는 성숙한 단계로 인도하라.
4. 심리학적 '인지적 재구성' 원리를 이용해 고난과 상황을 하나님의 섭리 안에서 재해석해주라.
5. 자리 양보와 같은 구체적 상황에 대해서는 갈라디아서 5:13의 '사랑으로 종 노릇 함'과 '복음 안에서의 참된 자유'를 연결하여 조언하라.

응답 구조:
- verse: 해당 성경 구절
- meditation: 신학적/심리학적 통찰이 담긴 깊은 묵상
- mentorWisdom: 상황에 대한 영성 멘토의 구체적이고 실천적인 조언
- application: 6단계 성찰을 포함한 구체적인 삶의 적용
- prayer: 5대 요소가 담긴 인격적인 대화체 기도문
- intercessoryPrayer: 공동체와 세상을 향한 확장된 중보기도
`;

export const generateMeditation = async (verseInput: string): Promise<MeditationResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `사용자의 상황 및 말씀: ${verseInput}`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verse: { type: Type.STRING },
          meditation: { type: Type.STRING },
          mentorWisdom: { type: Type.STRING },
          application: { type: Type.STRING },
          prayer: { type: Type.STRING },
          intercessoryPrayer: { type: Type.STRING }
        },
        required: ["verse", "meditation", "mentorWisdom", "application", "prayer", "intercessoryPrayer"]
      }
    },
  });

  const text = response.text;
  if (!text) throw new Error("결과 생성 실패");
  return JSON.parse(text);
};

