/**
 * Google Drive Service for saving meditations
 * Note: To use this in production, you need to set up a Project in Google Cloud Console
 * and obtain a CLIENT_ID.
 */

const CLIENT_ID = 'YOUR_GOOGLE_CLIENT_ID'; // 사용자가 발급받은 Client ID를 여기에 넣어야 합니다.
const SCOPES = 'https://www.googleapis.com/auth/drive.file';
const DISCOVERY_DOC = 'https://www.googleapis.com/discovery/v1/apis/drive/v3/rest';

let tokenClient: any;
let accessToken: string | null = null;

export const initGoogleApi = (): Promise<void> => {
  return new Promise((resolve) => {
    const gapi = (window as any).gapi;
    const google = (window as any).google;

    if (!gapi || !google) {
      console.warn("Google API scripts not loaded yet.");
      return;
    }

    gapi.load('client', async () => {
      await gapi.client.init({
        discoveryDocs: [DISCOVERY_DOC],
      });

      tokenClient = google.accounts.oauth2.initTokenClient({
        client_id: CLIENT_ID,
        scope: SCOPES,
        callback: (resp: any) => {
          if (resp.error !== undefined) {
            throw resp;
          }
          accessToken = resp.access_token;
          resolve();
        },
      });
      resolve();
    });
  });
};

export const connectDrive = (): Promise<void> => {
  return new Promise((resolve, reject) => {
    if (!tokenClient) {
      reject("Google Drive API not initialized");
      return;
    }
    tokenClient.callback = (resp: any) => {
      if (resp.error) return reject(resp);
      accessToken = resp.access_token;
      resolve();
    };
    tokenClient.requestAccessToken({ prompt: 'consent' });
  });
};

export const isConnected = () => !!accessToken;

async function getOrCreateFolder(folderName: string): Promise<string> {
  const gapi = (window as any).gapi;
  const response = await gapi.client.drive.files.list({
    q: `name = '${folderName}' and mimeType = 'application/vnd.google-apps.folder' and trashed = false`,
    fields: 'files(id, name)',
  });

  const files = response.result.files;
  if (files && files.length > 0) {
    return files[0].id;
  }

  const createResponse = await gapi.client.drive.files.create({
    resource: {
      name: folderName,
      mimeType: 'application/vnd.google-apps.folder',
    },
    fields: 'id',
  });

  return createResponse.result.id;
}

export const saveToDrive = async (fileName: string, content: string): Promise<void> => {
  if (!accessToken) throw new Error("Google Drive not connected");

  const gapi = (window as any).gapi;
  const folderId = await getOrCreateFolder("은혜의 묵상과 영적멘토링");

  const metadata = {
    name: fileName,
    mimeType: 'text/plain',
    parents: [folderId],
  };

  const boundary = '-------314159265358979323846';
  const delimiter = "\r\n--" + boundary + "\r\n";
  const close_delim = "\r\n--" + boundary + "--";

  const body =
    delimiter +
    'Content-Type: application/json; charset=UTF-8\r\n\r\n' +
    JSON.stringify(metadata) +
    delimiter +
    'Content-Type: text/plain\r\n\r\n' +
    content +
    close_delim;

  await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${accessToken}`,
      'Content-Type': `multipart/related; boundary=${boundary}`,
    },
    body: body,
  });
};

