interface Props {
  data: MeditationResult;
  onReset: () => void;
}

const MeditationDisplay: React.FC<Props> = ({ data, onReset }) => {
  const [copied, setCopied] = useState(false);

  const getFormattedContent = () => {
    return `
[말씀]
${data.verse}

[영성 멘토의 조언]
${data.mentorWisdom}

[묵상 (Meditation)]
${data.meditation}

